import React, { useRef, useEffect } from "react";

/**
 * Visualisation d'un automate avec Cytoscape.js (chargé via CDN).
 * Reçoit un objet automate au format :
 * { states, initial_state, final_states, transitions, alphabet }
 */
export default function AutomateGraph({
  automate,
  highlightState = null,
  style = {},
}) {
  const containerRef = useRef(null);
  const cyRef = useRef(null);

  useEffect(() => {
    if (!automate || !containerRef.current) return;
    if (!window.cytoscape) return;

    const cy = window.cytoscape;

    // Construire les noeuds
    const nodes = automate.states.map((state) => ({
      data: {
        id: state,
        label: state,
        isInitial: state === automate.initial_state,
        isFinal: automate.final_states.includes(state),
        isHighlighted: state === highlightState,
      },
    }));

    // Construire les arêtes en gérant t.to qui peut être
    // une string (DFA) ou un tableau de strings (NFA/ε-NFA).
    // On regroupe les symboles par paire (from, to) individuelle
    // pour éviter de passer une liste comme target à Cytoscape.
    const edgeMap = {}; // clé "from__to" → { from, to, symbols[] }

    automate.transitions.forEach((t) => {
      const sym = t.symbol === "" ? "ε" : t.symbol;
      // Normaliser t.to en tableau de destinations atomiques
      const destinations = Array.isArray(t.to) ? t.to : [t.to];

      destinations.forEach((dest) => {
        // Ignorer les destinations vides / malformées
        if (!dest) return;
        const key = `${t.from}__${dest}`;
        if (!edgeMap[key])
          edgeMap[key] = { from: t.from, to: dest, symbols: [] };
        // Eviter les doublons de symboles sur la même arête
        if (!edgeMap[key].symbols.includes(sym)) {
          edgeMap[key].symbols.push(sym);
        }
      });
    });

    const edges = Object.entries(edgeMap).map(([key, e]) => ({
      data: {
        id: `e_${key}`,
        source: e.from,
        target: e.to,
        label: e.symbols.sort().join(", "),
      },
    }));

    // Détruire l'instance précédente
    if (cyRef.current) cyRef.current.destroy();

    cyRef.current = cy({
      container: containerRef.current,
      elements: [...nodes, ...edges],
      style: [
        {
          selector: "node",
          style: {
            label: "data(label)",
            "text-valign": "center",
            "text-halign": "center",
            "background-color": "#1a1e28",
            "border-color": "#2e3547",
            "border-width": 2,
            color: "#e2e8f0",
            "font-family": "Space Mono, monospace",
            "font-size": "11px",
            width: 44,
            height: 44,
          },
        },
        {
          selector: "node[?isFinal]",
          style: {
            "border-color": "#00e5ff",
            "border-width": 3,
            "background-color": "#0d1a1f",
            "box-shadow": "0 0 12px rgba(0,229,255,0.4)",
          },
        },
        {
          selector: "node[?isInitial]",
          style: {
            "background-color": "#1a1428",
            "border-color": "#7c3aed",
            "border-width": 3,
          },
        },
        {
          selector: "node[?isHighlighted]",
          style: {
            "background-color": "#1a2a1a",
            "border-color": "#10b981",
            "border-width": 4,
          },
        },
        {
          selector: "edge",
          style: {
            label: "data(label)",
            width: 2,
            "line-color": "#2e3547",
            "target-arrow-color": "#2e3547",
            "target-arrow-shape": "triangle",
            "curve-style": "bezier",
            color: "#94a3b8",
            "font-family": "Space Mono, monospace",
            "font-size": "10px",
            "text-background-color": "#0d0f14",
            "text-background-opacity": 1,
            "text-background-padding": "3px",
          },
        },
        {
          selector: "edge[source = target]",
          style: { "curve-style": "loop" },
        },
      ],
      layout: {
        name: automate.states.length <= 6 ? "circle" : "breadthfirst",
        directed: true,
        padding: 30,
        spacingFactor: 1.4,
      },
    });

    return () => {
      if (cyRef.current) cyRef.current.destroy();
    };
  }, [automate, highlightState]);

  if (!automate) {
    return (
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          height: "100%",
          color: "#475569",
          fontFamily: "Space Mono, monospace",
          fontSize: "12px",
          ...style,
        }}
      >
        Aucun automate à afficher
      </div>
    );
  }

  return (
    <div
      ref={containerRef}
      style={{
        width: "100%",
        height: "320px",
        background: "#0d0f14",
        borderRadius: "8px",
        border: "1px solid #252a38",
        ...style,
      }}
    />
  );
}
